import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

import org.apache.commons.text.StringEscapeUtils; // Import Apache Commons Text library for escaping HTML characters

public class XSSFixedServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {

        String userInput = request.getParameter("input");
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput); // Sanitize user input

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Welcome " + sanitizedInput + "</h1>"); // Safe output with sanitized user input
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
